+    #[test]
+    fn reservation_serde_roundtrip_full() {
+        let res = ResourceReservation {
+            id: "res_42".into(),
+            agent: agent("SunnyMoose"),
+            connector: "slack".into(),
+            resource: "channel:general".into(),
+            reserved_at: 1_000_000,
+            ttl_seconds: 7200,
