+        assert_eq!(
+            hub.check_conflict(&agent("A"), "github", None),
+            ConflictCheck::Clear
+        );
+    }
+
+    #[test]
+    fn conflict_check_expired_reservation_not_blocked() {
+        let mut hub = CoordinationHub::new();
+        hub.reservations.insert(
+            "expired_res".into(),
+            ResourceReservation {
+                id: "expired_res".into(),
+                agent: agent("B"),
+                connector: "github".into(),
+                resource: "repo:x".into(),
