+        );
+        assert!(validate_tool_call(&reg, "github.list_repos", &zone_work(), Some(&token)).is_err());
+        // slack.send_message not denied
+        assert!(validate_tool_call(&reg, "slack.send_message", &zone_work(), Some(&token)).is_ok());
+    }
